from flask import Flask, request, session, redirect, url_for, render_template_string
import xml.etree.ElementTree as ET
from datetime import datetime
import base64
import hashlib
import uuid

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

SAML_NAMESPACES = {
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'xs': 'http://www.w3.org/2001/XMLSchema',
    'xsi': 'http://www.w3.org/2001/XMLSchema-instance'
}

def parse_saml_response(saml_response):
    try:
        # Decode base64 encoded SAML response
        decoded_response = base64.b64decode(saml_response)
        
        # Parse XML
        root = ET.fromstring(decoded_response)
        
        # Validate SAML response structure
        response_element = root.find('.//samlp:Response', namespaces=SAML_NAMESPACES)
        if response_element is None:
            raise ValueError("Invalid SAML response: No Response element found")
        
        # Extract assertion
        assertion = response_element.find('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if assertion is None:
            raise ValueError("Invalid SAML response: No Assertion element found")
        
        # Validate assertion
        assertion_id = assertion.get('ID')
        if not assertion_id:
            raise ValueError("Invalid SAML assertion: Missing ID attribute")
        
        # Extract user attributes
        attributes = {}
        attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
        
        for attr_statement in attribute_statements:
            attribute_elements = attr_statement.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES)
            for attr in attribute_elements:
                attr_name = attr.get('Name')
                if attr_name:
                    attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
                    if attr_values:
                        values = [val.text for val in attr_values if val.text]
                        attributes[attr_name] = values[0] if len(values) == 1 else values
        
        # Extract subject (user identifier)
        subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
        subject_name = None
        if subject is not None:
            name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
            if name_id is not None:
                subject_name = name_id.text
        
        # Extract issuer
        issuer = assertion.find('.//saml:Issuer', namespaces=SAML_NAMESPACES)
        issuer_name = issuer.text if issuer is not None else None
        
        # Extract conditions
        conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NAMESPACES)
        not_before = None
        not_on_or_after = None
        if conditions is not None:
            not_before = conditions.get('NotBefore')
            not_on_or_after = conditions.get('NotOnOrAfter')
        
        return {
            'assertion_id': assertion_id,
            'subject': subject_name,
            'issuer': issuer_name,
            'attributes': attributes,
            'not_before': not_before,
            'not_on_or_after': not_on_or_after,
            'valid': True
        }
        
    except Exception as e:
        return {'valid': False, 'error': str(e)}

def create_user_session(user_info):
    session['user_id'] = user_info.get('subject')
    session['user_attributes'] = user_info.get('attributes', {})
    session['session_id'] = str(uuid.uuid4())
    session['login_time'] = datetime.now().isoformat()
    session['logged_in'] = True

@app.route('/saml/login', methods=['POST'])
def saml_login():
    try:
        saml_response = request.form.get('SAMLResponse')
        if not saml_response:
            return "Missing SAML Response", 400
        
        # Parse SAML response
        parsed_data = parse_saml_response(saml_response)
        
        if not parsed_data.get('valid'):
            return f"Invalid SAML response: {parsed_data.get('error')}", 400
        
        # Create user session
        create_user_session(parsed_data)
        
        return redirect(url_for('dashboard'))
        
    except Exception as e:
        return f"Error processing SAML response: {str(e)}", 500

@app.route('/dashboard')
def dashboard():
    if not session.get('logged_in'):
        return redirect(url_for('login'))
    
    user_id = session.get('user_id')
    attributes = session.get('user_attributes', {})
    
    template = """
    <html>
        <head><title>Dashboard</title></head>
        <body>
            <h1>Welcome, {{ user_id }}!</h1>
            <h2>User Attributes:</h2>
            <ul>
                {% for key, value in attributes.items() %}
                <li><strong>{{ key }}:</strong> {{ value }}</li>
                {% endfor %}
            </ul>
            <a href="/logout">Logout</a>
        </body>
    </html>
    """
    
    return render_template_string(template, user_id=user_id, attributes=attributes)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

